AG,'N'),CASE  WHEN FCT_ENTITY_INFO_CUST.V_PARTY_ID IS NOT NULL AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS','PRCS','FAGR','PRAGR') THEN  'Y' ELSE 'N'   END,'1',DIM_PARTY_CUST.n_party_skey,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN CASE WHEN STG_UNDERLYING_EXPOSURES.n_residual_maturity is NULL THEN DAYS_BETWEEN(STG_UNDERLYING_EXPOSURES.fic_mis_date, STG_UNDERLYING_EXPOSURES.d_exposure_end_date, STG_UNDERLYING_EXPOSURES.v_day_count_ind) else STG_UNDERLYING_EXPOSURES.n_residual_maturity END ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_UNDERLYING_EXPOSURES.N_EXPOSURE_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_UNDERLYING_EXPOSURES.N_MTM_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_UNDERLYING_EXPOSURES.N_TRANCHE_SENIORITY_POSITION,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN STG_UNDERLYING_EXPOSURES.N_ORIGINAL_MATURITY is NULL THEN DAYS_BETWEEN(STG_UNDERLYING_EXPOSURES.D_EXPOSURE_START_DATE, STG_UNDERLYING_EXPOSURES.D_EXPOSURE_END_DATE, STG_UNDERLYING_EXPOSURES.V_DAY_COUNT_IND) else STG_UNDERLYING_EXPOSURES.N_ORIGINAL_MATURITY END,FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DIM_PARENT_EXPOSURE.N_ACCT_SKEY,CASE WHEN STG_UNDERLYING_EXPOSURES.n_residual_maturity is NULL THEN DAYS_BETWEEN(STG_UNDERLYING_EXPOSURES.fic_mis_date, STG_UNDERLYING_EXPOSURES.d_exposure_end_date, STG_UNDERLYING_EXPOSURES.v_day_count_ind) else STG_UNDERLYING_EXPOSURES.n_residual_maturity END,RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY,'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,'STG_UNDERLYING_EXPOSURES',FSI_CAP_RUN_EXE_PARAMETERS.V_RCY_CODE,CASE WHEN SEC_POOL_MASTER.N_SEC_POOL_SKEY IS NOT NULL THEN 'SEC' ELSE STG_UNDERLYING_EXPOSURES.V_UNDERLYING_DATA_IDENTIFIER END,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FCT_INSTRUMENT_CONTRACT_DTL.N_ISSUE_DATE_SKEY),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_UNDERLYING_TYPE_SKEY),to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),STG_UNDERLYING_EXPOSURES.F_DEF_DUE_CREDIT_WORTHINESS,STG_UNDERLYING_EXPOSURES.F_ELIGIBLE_PROTECTION_IND,STG_UNDERLYING_EXPOSURES.F_EQUITY_POSITION_FLAG,STG_UNDERLYING_EXPOSURES.F_EQUITY_TRADED_FLAG,STG_UNDERLYING_EXPOSURES.F_EXP_DEFAULTED_FLAG,STG_UNDERLYING_EXPOSURES.F_GUAR_BY_ELIG_GUARANTOR_IND,STG_UNDERLYING_EXPOSURES.F_MAIN_INDEX_IND,STG_UNDERLYING_EXPOSURES.F_PAST_DUE_FLAG,STG_UNDERLYING_EXPOSURES.F_SECURITIZED_FLAG,STG_UNDERLYING_EXPOSURES.F_SENIOR_UNIT_ELIG_SEC_FLAG,to_char(STG_UNDERLYING_EXPOSURES.N_DELINQUENT_DAYS),to_char(STG_UNDERLYING_EXPOSURES.N_EXP_LTI_RATIO),to_char(STG_UNDERLYING_EXPOSURES.N_EXP_LTV_RATIO),to_char(STG_UNDERLYING_EXPOSURES.N_LGD_PERCENT),to_char(STG_UNDERLYING_EXPOSURES.N_LOAD_RUN_ID),to_char(STG_UNDERLYING_EXPOSURES.N_PD_PERCENT),to_char(STG_UNDERLYING_EXPOSURES.N_PRINCIPAL_BALANCE),STG_UNDERLYING_EXPOSURES.V_CCY_CODE FROM STG_UNDERLYING_EXPOSURES INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = STG_UNDERLYING_EXPOSURES.FIC_MIS_DATE AND DIM_DATES.d_calendar_date = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON STG_UNDERLYING_EXPOSURES.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.d_record_start_date AND DIM_EXPOSURE.d_record_end_date LEFT JOIN DIM_PRODUCT ON STG_UNDERLYING_EXPOSURES.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.d_record_start_date AND DIM_PRODUCT.d_record_end_date LEFT JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT JOIN DIM_GAAP ON STG_UNDERLYING_EXPOSURES.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.d_record_end_date LEFT JOIN DIM_ISSUE ON COALESCE(STG_UNDERLYING_EXPOSURES.V_EXPOSURE_ID, DIM_EXPOSURE.V_EXPOSURE_ID) = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_UNDERLYING_EXPOSURES.V_PARENT_EXPOSURE_ID = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARENT_EXPOSURE.d_record_start_date AND DIM_PARENT_EXPOSURE.d_record_end_date LEFT JOIN DIM_PARTY ON COALESCE(STG_UNDERLYING_EXPOSURES.V_ISSUER_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.d_record_start_date AND DIM_PARTY.d_record_end_date LEFT JOIN DIM_PARTY DIM_PARTY_CUST ON COALESCE(STG_UNDERLYING_EXPOSURES.V_CUST_CODE, 'MSG') = DIM_PARTY_CUST.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_CUST.d_record_start_date AND DIM_PARTY_CUST.d_record_end_date INNER JOIN DIM_PARTY_TYPE ON COALESCE(COALESCE(DIM_PARTY.V_PARTY_TYPE, DIM_PARTY_CUST.V_PARTY_TYPE), 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.d_record_start_date AND DIM_PARTY_TYPE.d_record_end_date LEFT JOIN DIM_COUNTRY ON COALESCE(STG_UNDERLYING_EXPOSURES.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.d_record_start_date AND DIM_COUNTRY.d_record_end_date INNER JOIN FCT_ENTITY_INFO ON STG_UNDERLYING_EXPOSURES.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO.n_Mis_Date_Skey = DIM_DATES.N_DATE_SKEY LEFT JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY LEFT JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = '870' AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = COALESCE(DIM_PARTY.N_PARTY_SKEY, DIM_PARTY_CUST.N_PARTY_SKEY) LEFT JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.d_record_start_date AND DIM_LOCATION.d_record_end_date LEFT JOIN DIM_EXPOSURE_UNDERLYING_TYPE ON DIM_EXPOSURE_UNDERLYING_TYPE.V_UNDERLYING_TYPE_CODE = STG_UNDERLYING_EXPOSURES.V_UNDERLYING_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_UNDERLYING_TYPE.d_record_start_date AND DIM_EXPOSURE_UNDERLYING_TYPE.d_record_end_date LEFT JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_UNDERLYING_EXPOSURES.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.d_record_start_date AND DIM_INSTRUMENT_CONTRACT.d_record_end_date LEFT JOIN FCT_INSTRUMENT_CONTRACT_DTL ON FCT_INSTRUMENT_CONTRACT_DTL.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY AND FCT_INSTRUMENT_CONTRACT_DTL.N_RUN_SKEY = '870' AND FCT_INSTRUMENT_CONTRACT_DTL.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT OUTER JOIN SEC_POOL_MASTER ON SEC_POOL_MASTER.V_SEC_POOL_ID = STG_UNDERLYING_EXPOSURES.V_SEC_POOL_ID AND to_date('20260331','YYYYMMDD') BETWEEN SEC_POOL_MASTER.D_RECORD_START_DATE AND SEC_POOL_MASTER.D_RECORD_END_DATE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_UNDERLYING_EXPOSURES.V_CCY_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_PROD_TXN_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_ULY' LEFT JOIN FSI_INSTR_VALUATION_DETAILS ON FSI_INSTR_VALUATION_DETAILS.V_INSTRUMENT_CODE = STG_UNDERLYING_EXPOSURES.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN FSI_INSTR_VALUATION_DETAILS.D_RECORD_START_DATE AND FSI_INSTR_VALUATION_DETAILS.D_RECORD_END_DATE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION C_FSI_CAP_CURRENCY_CONVERSION ON C_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND C_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND C_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_INSTR_VALUATION_DETAILS.V_CCY_CODE LEFT JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = '870' AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN DIM_BASEL_METHODOLOGY ON DIM_BASEL_METHODOLOGY.V_BASEL_METHOD_CODE = FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BASEL_METHODOLOGY.D_RECORD_START_DATE AND DIM_BASEL_METHODOLOGY.D_RECORD_END_DATE LEFT JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO_CUST.v_party_id = STG_UNDERLYING_EXPOSURES.v_issuer_code AND FCT_ENTITY_INFO_CUST.f_cap_consl_entity_ind = 'Y' AND FCT_ENTITY_INFO_CUST.n_run_skey = '870' LEFT JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.n_basel_cap_consl_appr_skey = FCT_ENTITY_INFO_CUST.n_basel_cap_consl_appr_skey AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) LEFT JOIN DIM_BANK_INSTRUMENT_TYPE ON DIM_BANK_INSTRUMENT_TYPE.V_BANK_INSTR_TYPE_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTR_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BANK_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_BANK_INSTRUMENT_TYPE.D_RECORD_END_DATE LEFT JOIN FSI_INSTR_TYPE_CLASSIFICATION ON DIM_BANK_INSTRUMENT_TYPE.N_BANK_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_BANK_INSTR_TYPE_SKEY AND FSI_INSTR_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_INSTR_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN FSI_INSTR_TYPE_ULY_TYPE_RECLS ON FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_RUN_SKEY = '870' AND FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE WHERE 1=1 AND DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CATGRY_CD IN ( 'DEBT' ,'SECR' ) AND (STG_UNDERLYING_EXPOSURES.V_UNDERLYING_DATA_IDENTIFIER IS NULL OR STG_UNDERLYING_EXPOSURES.V_UNDERLYING_DATA_IDENTIFIER NOT IN ('MLT','REPO')) AND SEC_POOL_MASTER.V_SEC_POOL_ID IS NULL AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = STG_UNDERLYING_EXPOSURES.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = STG_UNDERLYING_EXPOSURES.FIC_MIS_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = STG_UNDERLYING_EXPOSURES.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_UNDERLYING_EXPOSURES.N_LOAD_RUN_ID ) AND (CASE WHEN STG_UNDERLYING_EXPOSURES.n_residual_maturity is NULL THEN DAYS_BETWEEN(STG_UNDERLYING_EXPOSURES.fic_mis_date, STG_UNDERLYING_EXPOSURES.d_exposure_end_date, STG_UNDERLYING_EXPOSURES.v_day_count_ind) else STG_UNDERLYING_EXPOSURES.n_residual_maturity END>0) LOG ERRORS INTO FSI_CAP_INVESTMENT_EXPOSURES$ ('1776768470765_39070575_20260331_1_Job_d7242195003f4f628e1522c6e7838257') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
